#include <stdio.h>

int main() {
    int start, end, divisor;

    // Read the three integers from standard input
    scanf("%d %d %d", &start, &end, &divisor);

    int sum_of_multiples = 0;

    // Loop through the range from 'start' to 'end' (inclusive)
    for (int i = start; i <= end; i++) {
        // Check if the current number 'i' is a multiple of 'divisor'
        // A number 'i' is a multiple of 'divisor' if the remainder of i / divisor is 0
        if (i % divisor == 0) {
            sum_of_multiples += i; // Add 'i' to the sum if it's a multiple
        }
    }

    // Print the final sum to standard output, followed by a newline
    printf("%d\n", sum_of_multiples);

    return 0;
}
